/**
 * Claude Code Settings Manager
 *
 * Reads and writes .claude/settings.json with a safe merge strategy:
 * only AutomatosX-managed keys are written; user-managed keys are preserved.
 *
 * Note: .claude/ is gitignored. settings.json is a local setup artifact
 * generated by `ax setup --claude-code`. For team-shared MCP config use .mcp.json.
 *
 * @module integrations/claude-code/settings-manager
 */

import { mkdir } from 'fs/promises';
import { join } from 'path';
import { logger } from '../../shared/logging/logger.js';
import { ClaudeCodeError, ClaudeCodeErrorType } from './types.js';
import { fileExists, readJsonFile, writeJsonFile } from './utils/file-reader.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Permission allow/deny entry */
type PermissionEntry = string;

/** Claude Code settings.json schema (partial — only what we manage) */
export interface ClaudeCodeSettings {
  $schema?: string;
  permissions?: {
    allow?: PermissionEntry[];
    deny?: PermissionEntry[];
  };
  hooks?: Record<string, unknown>;
  /** Preserved user-managed fields */
  [key: string]: unknown;
}

/** Result of a settings write operation */
export interface SettingsWriteResult {
  path: string;
  created: boolean;
  permissionsAdded: string[];
}

// ─── Constants ────────────────────────────────────────────────────────────────

const SETTINGS_SCHEMA = 'https://json.schemastore.org/claude-code-settings.json';

/** MCP tool permissions AutomatosX requires */
const AUTOMATOSX_MCP_PERMISSIONS: PermissionEntry[] = [
  'mcp__automatosx__run_agent',
  'mcp__automatosx__list_agents',
  'mcp__automatosx__search_memory',
  'mcp__automatosx__get_status',
  'mcp__automatosx__session_create',
  'mcp__automatosx__session_list',
  'mcp__automatosx__session_status',
  'mcp__automatosx__session_complete',
  'mcp__automatosx__session_fail',
  'mcp__automatosx__memory_add',
  'mcp__automatosx__memory_list',
  'mcp__automatosx__memory_delete',
  'mcp__automatosx__memory_export',
  'mcp__automatosx__memory_import',
  'mcp__automatosx__memory_stats',
  'mcp__automatosx__memory_clear',
];

// ─── SettingsManager ─────────────────────────────────────────────────────────

export class SettingsManager {
  private projectDir: string;

  constructor(projectDir: string) {
    this.projectDir = projectDir;
  }

  private get settingsPath(): string {
    return join(this.projectDir, '.claude', 'settings.json');
  }

  /**
   * Read existing settings.json, returning empty object if absent.
   */
  async read(): Promise<ClaudeCodeSettings> {
    if (!(await fileExists(this.settingsPath))) {
      return {};
    }
    try {
      return await readJsonFile<ClaudeCodeSettings>(this.settingsPath);
    } catch (error) {
      logger.warn('[SettingsManager] Could not parse settings.json — starting fresh', { error });
      return {};
    }
  }

  /**
   * Merge AutomatosX MCP permissions into settings.json without touching
   * any other user-managed keys.
   *
   * Strategy:
   * - Read existing settings (or empty object)
   * - Add $schema if not present
   * - Merge permissions.allow: add missing entries, never remove existing ones
   * - Write back
   */
  async writeMcpPermissions(): Promise<SettingsWriteResult> {
    logger.info('[SettingsManager] Merging MCP permissions into settings.json...');

    const existed = await fileExists(this.settingsPath);
    const settings = await this.read();

    // Ensure $schema
    if (!settings.$schema) {
      settings.$schema = SETTINGS_SCHEMA;
    }

    // Ensure permissions object
    if (!settings.permissions) {
      settings.permissions = {};
    }
    if (!Array.isArray(settings.permissions.allow)) {
      settings.permissions.allow = [];
    }

    // Add only missing permissions (never remove existing)
    const existing = new Set(settings.permissions.allow);
    const added: string[] = [];
    for (const perm of AUTOMATOSX_MCP_PERMISSIONS) {
      if (!existing.has(perm)) {
        settings.permissions.allow.push(perm);
        added.push(perm);
      }
    }

    await this.ensureClaudeDir();
    await writeJsonFile(this.settingsPath, settings);

    logger.info('[SettingsManager] settings.json updated', {
      path: this.settingsPath,
      created: !existed,
      permissionsAdded: added.length,
    });

    return {
      path: this.settingsPath,
      created: !existed,
      permissionsAdded: added,
    };
  }

  /**
   * Check whether settings.json exists and contains AutomatosX permissions.
   */
  async hasAutomatosXPermissions(): Promise<boolean> {
    if (!(await fileExists(this.settingsPath))) {
      return false;
    }
    try {
      const settings = await this.read();
      const allow = settings.permissions?.allow ?? [];
      return AUTOMATOSX_MCP_PERMISSIONS.every((p) => allow.includes(p));
    } catch {
      return false;
    }
  }

  /**
   * Return path to the settings file.
   */
  getSettingsPath(): string {
    return this.settingsPath;
  }

  // ─── Private ───────────────────────────────────────────────────────────────

  private async ensureClaudeDir(): Promise<void> {
    const claudeDir = join(this.projectDir, '.claude');
    try {
      await mkdir(claudeDir, { recursive: true });
    } catch (error) {
      throw new ClaudeCodeError(
        ClaudeCodeErrorType.FILE_ERROR,
        `Failed to create .claude directory: ${claudeDir}`,
        { error }
      );
    }
  }
}
